import{_ as e,c as a,m as s,a as p,t as l,a5 as i,o as c}from"./chunks/framework.DwbewbAn.js";const k=JSON.parse('{"title":"Explain 详解（上）","description":"","frontmatter":{"title":"Explain 详解（上）"},"headers":[],"relativePath":"doc/数据库/Mysql/基础/执行计划/explain详解上.md","filePath":"packages/doc/src/数据库/Mysql/基础/执行计划/explain详解上.md","lastUpdated":1711622925000}'),d={name:"doc/数据库/Mysql/基础/执行计划/explain详解上.md"},r={id:"frontmatter-title",tabindex:"-1"},o=s("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),t=i(`<p>官方链接：<a href="https://dev.mysql.com/doc/refman/5.7/en/explain-output.html" target="_blank" rel="noreferrer">https://dev.mysql.com/doc/refman/5.7/en/explain-output.html</a></p><hr><p>一条查询语句在经过<code>MySQL</code>查询优化器的各种基于成本和规则的优化会后生成一个所谓的<code>执行计划</code>，这个执行计划展示了接下来具体执行查询的方式，比如多表连接的顺序是什么，对于每个表采用什么访问方法来具体执行查询等等。设计<code>MySQL</code>的大叔贴心的为我们提供了<code>EXPLAIN</code>语句来帮助我们查看某个查询语句的具体执行计划，本章的内容就是为了帮助大家看懂<code>EXPLAIN</code>语句的各个输出项都是干嘛使的，从而可以有针对性的提升我们查询语句的性能。</p><p>如果我们想看看某个查询的执行计划的话，可以在具体的查询语句前边加一个<code>EXPLAIN</code>，就像这样：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT 1;</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+------+---------+------+------+----------+----------------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type | possible_keys | key  | key_len | ref  | rows | filtered | Extra          |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+------+---------+------+------+----------+----------------+</span></span>
<span class="line"><span>|  1 | SIMPLE      | NULL  | NULL       | NULL | NULL          | NULL | NULL    | NULL | NULL |     NULL | No tables used |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+------+---------+------+------+----------+----------------+</span></span>
<span class="line"><span>1 row in set, 1 warning (0.01 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>然后这输出的一大坨东西就是所谓的<code>执行计划</code>，我的任务就是带领大家看懂这一大坨东西里边的每个列都是干啥用的，以及在这个<code>执行计划</code>的辅助下，我们应该怎样改进自己的查询语句以使查询执行起来更高效。其实除了以<code>SELECT</code>开头的查询语句，其余的<code>DELETE</code>、<code>INSERT</code>、<code>REPLACE</code>以及<code>UPDATE</code>语句前边都可以加上<code>EXPLAIN</code>这个词儿，用来查看这些语句的执行计划，不过我们这里对<code>SELECT</code>语句更感兴趣，所以后边只会以<code>SELECT</code>语句为例来描述<code>EXPLAIN</code>语句的用法。为了让大家先有一个感性的认识，我们把<code>EXPLAIN</code>语句输出的各个列的作用先大致罗列一下：</p><table><thead><tr><th>列名</th><th>描述</th></tr></thead><tbody><tr><td><code>id</code></td><td>在一个大的查询语句中每个<code>SELECT</code>关键字都对应一个唯一的<code>id</code></td></tr><tr><td><code>select_type</code></td><td><code>SELECT</code>关键字对应的那个查询的类型</td></tr><tr><td><code>table</code></td><td>表名</td></tr><tr><td><code>partitions</code></td><td>匹配的分区信息</td></tr><tr><td><code>type</code></td><td>针对单表的访问方法</td></tr><tr><td><code>possible_keys</code></td><td>可能用到的索引</td></tr><tr><td><code>key</code></td><td>实际上使用的索引</td></tr><tr><td><code>key_len</code></td><td>实际使用到的索引长度</td></tr><tr><td><code>ref</code></td><td>当使用索引列等值查询时，与索引列进行等值匹配的对象信息</td></tr><tr><td><code>rows</code></td><td>预估的需要读取的记录条数</td></tr><tr><td><code>filtered</code></td><td>某个表经过搜索条件过滤后剩余记录条数的百分比</td></tr><tr><td><code>Extra</code></td><td>一些额外的信息</td></tr></tbody></table><p>需要注意的是，大家如果看不懂上边输出列含义，那是正常的，千万不要纠结～。我在这里把它们都列出来只是为了描述一个轮廓，让大家有一个大致的印象，下边会细细道来，等会儿说完了不信你不会～ 为了故事的顺利发展，我们还是要请出我们前边已经用了n遍的<code>single_table</code>表，为了防止大家忘了，再把它的结构描述一遍：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>CREATE TABLE single_table (</span></span>
<span class="line"><span>    id INT NOT NULL AUTO_INCREMENT,</span></span>
<span class="line"><span>    key1 VARCHAR(100),</span></span>
<span class="line"><span>    key2 INT,</span></span>
<span class="line"><span>    key3 VARCHAR(100),</span></span>
<span class="line"><span>    key_part1 VARCHAR(100),</span></span>
<span class="line"><span>    key_part2 VARCHAR(100),</span></span>
<span class="line"><span>    key_part3 VARCHAR(100),</span></span>
<span class="line"><span>    common_field VARCHAR(100),</span></span>
<span class="line"><span>    PRIMARY KEY (id),</span></span>
<span class="line"><span>    KEY idx_key1 (key1),</span></span>
<span class="line"><span>    UNIQUE KEY idx_key2 (key2),</span></span>
<span class="line"><span>    KEY idx_key3 (key3),</span></span>
<span class="line"><span>    KEY idx_key_part(key_part1, key_part2, key_part3)</span></span>
<span class="line"><span>) Engine=InnoDB CHARSET=utf8;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><p>我们仍然假设有两个和<code>single_table</code>表构造一模一样的<code>s1</code>、<code>s2</code>表，而且这两个表里边儿有10000条记录，除id列外其余的列都插入随机值。为了让大家有比较好的阅读体验，我们下边并不准备严格按照<code>EXPLAIN</code>输出列的顺序来介绍这些列分别是干嘛的，大家注意一下就好了。</p><h2 id="执行计划输出中各列详解" tabindex="-1">执行计划输出中各列详解 <a class="header-anchor" href="#执行计划输出中各列详解" aria-label="Permalink to &quot;执行计划输出中各列详解&quot;">​</a></h2><h3 id="table" tabindex="-1">table <a class="header-anchor" href="#table" aria-label="Permalink to &quot;table&quot;">​</a></h3><p>不论我们的查询语句有多复杂，里边儿包含了多少个表，到最后也是需要对每个表进行单表访问的，所以设计<code>MySQL</code>的大叔规定EXPLAIN语句输出的每条记录都对应着某个单表的访问方法，该条记录的table列代表着该表的表名。所以我们看一条比较简单的查询语句：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1;</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+------+---------+------+------+----------+-------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type | possible_keys | key  | key_len | ref  | rows | filtered | Extra |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+------+---------+------+------+----------+-------+</span></span>
<span class="line"><span>|  1 | SIMPLE      | s1    | NULL       | ALL  | NULL          | NULL | NULL    | NULL | 9688 |   100.00 | NULL  |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+------+---------+------+------+----------+-------+</span></span>
<span class="line"><span>1 row in set, 1 warning (0.00 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>这个查询语句只涉及对<code>s1</code>表的单表查询，所以<code>EXPLAIN</code>输出中只有一条记录，其中的<code>table</code>列的值是<code>s1</code>，表明这条记录是用来说明对<code>s1</code>表的单表访问方法的。</p><p>下边我们看一下一个连接查询的执行计划：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1 INNER JOIN s2;</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+------+---------+------+------+----------+---------------------------------------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type | possible_keys | key  | key_len | ref  | rows | filtered | Extra                                 |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+------+---------+------+------+----------+---------------------------------------+</span></span>
<span class="line"><span>|  1 | SIMPLE      | s1    | NULL       | ALL  | NULL          | NULL | NULL    | NULL | 9688 |   100.00 | NULL                                  |</span></span>
<span class="line"><span>|  1 | SIMPLE      | s2    | NULL       | ALL  | NULL          | NULL | NULL    | NULL | 9954 |   100.00 | Using join buffer (Block Nested Loop) |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+------+---------+------+------+----------+---------------------------------------+</span></span>
<span class="line"><span>2 rows in set, 1 warning (0.01 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>可以看到这个连接查询的执行计划中有两条记录，这两条记录的<code>table</code>列分别是<code>s1</code>和<code>s2</code>，这两条记录用来分别说明对<code>s1</code>表和<code>s2</code>表的访问方法是什么。</p><h3 id="id" tabindex="-1">id <a class="header-anchor" href="#id" aria-label="Permalink to &quot;id&quot;">​</a></h3><p>我们知道我们写的查询语句一般都以<code>SELECT</code>关键字开头，比较简单的查询语句里只有一个<code>SELECT</code>关键字，比如下边这个查询语句：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>SELECT * FROM s1 WHERE key1 = &#39;a&#39;;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>稍微复杂一点的连接查询中也只有一个<code>SELECT</code>关键字，比如：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>SELECT * FROM s1 INNER JOIN s2</span></span>
<span class="line"><span>    ON s1.key1 = s2.key1</span></span>
<span class="line"><span>    WHERE s1.common_field = &#39;a&#39;;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>但是下边两种情况下在一条查询语句中会出现多个<code>SELECT</code>关键字：</p><ul><li><p>查询中包含子查询的情况</p><p>比如下边这个查询语句中就包含2个<code>SELECT</code>关键字：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>SELECT * FROM s1 </span></span>
<span class="line"><span>    WHERE key1 IN (SELECT key3 FROM s2);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div></li><li><p>查询中包含<code>UNION</code>语句的情况</p><p>比如下边这个查询语句中也包含2个<code>SELECT</code>关键字：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>SELECT * FROM s1  UNION SELECT * FROM s2;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li></ul><p>查询语句中每出现一个<code>SELECT</code>关键字，设计<code>MySQL</code>的大叔就会为它分配一个唯一的<code>id</code>值。这个<code>id</code>值就是<code>EXPLAIN</code>语句的第一个列，比如下边这个查询中只有一个<code>SELECT</code>关键字，所以<code>EXPLAIN</code>的结果中也就只有一条<code>id</code>列为<code>1</code>的记录：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1 WHERE key1 = &#39;a&#39;;</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+----------+---------+-------+------+----------+-------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type | possible_keys | key      | key_len | ref   | rows | filtered | Extra |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+----------+---------+-------+------+----------+-------+</span></span>
<span class="line"><span>|  1 | SIMPLE      | s1    | NULL       | ref  | idx_key1      | idx_key1 | 303     | const |    8 |   100.00 | NULL  |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+----------+---------+-------+------+----------+-------+</span></span>
<span class="line"><span>1 row in set, 1 warning (0.03 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>对于连接查询来说，一个<code>SELECT</code>关键字后边的<code>FROM</code>子句中可以跟随多个表，所以在连接查询的执行计划中，每个表都会对应一条记录，但是这些记录的id值都是相同的，比如：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1 INNER JOIN s2;</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+------+---------+------+------+----------+---------------------------------------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type | possible_keys | key  | key_len | ref  | rows | filtered | Extra                                 |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+------+---------+------+------+----------+---------------------------------------+</span></span>
<span class="line"><span>|  1 | SIMPLE      | s1    | NULL       | ALL  | NULL          | NULL | NULL    | NULL | 9688 |   100.00 | NULL                                  |</span></span>
<span class="line"><span>|  1 | SIMPLE      | s2    | NULL       | ALL  | NULL          | NULL | NULL    | NULL | 9954 |   100.00 | Using join buffer (Block Nested Loop) |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+------+---------+------+------+----------+---------------------------------------+</span></span>
<span class="line"><span>2 rows in set, 1 warning (0.01 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>可以看到，上述连接查询中参与连接的<code>s1</code>和<code>s2</code>表分别对应一条记录，但是这两条记录对应的<code>id</code>值都是<code>1</code>。这里需要大家记住的是，在连接查询的执行计划中，每个表都会对应一条记录，这些记录的id列的值是相同的，出现在前边的表表示驱动表，出现在后边的表表示被驱动表。所以从上边的<code>EXPLAIN</code>输出中我们可以看出，查询优化器准备让<code>s1</code>表作为驱动表，让<code>s2</code>表作为被驱动表来执行查询。</p><p>对于包含子查询的查询语句来说，就可能涉及多个<code>SELECT</code>关键字，所以在包含子查询的查询语句的执行计划中，每个<code>SELECT</code>关键字都会对应一个唯一的<code>id</code>值，比如这样：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1 WHERE key1 IN (SELECT key1 FROM s2) OR key3 = &#39;a&#39;;</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------+---------------+----------+---------+------+------+----------+-------------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type  | possible_keys | key      | key_len | ref  | rows | filtered | Extra       |</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------+---------------+----------+---------+------+------+----------+-------------+</span></span>
<span class="line"><span>|  1 | PRIMARY     | s1    | NULL       | ALL   | idx_key3      | NULL     | NULL    | NULL | 9688 |   100.00 | Using where |</span></span>
<span class="line"><span>|  2 | SUBQUERY    | s2    | NULL       | index | idx_key1      | idx_key1 | 303     | NULL | 9954 |   100.00 | Using index |</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------+---------------+----------+---------+------+------+----------+-------------+</span></span>
<span class="line"><span>2 rows in set, 1 warning (0.02 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>从输出结果中我们可以看到，<code>s1</code>表在外层查询中，外层查询有一个独立的<code>SELECT</code>关键字，所以第一条记录的<code>id</code>值就是<code>1</code>，<code>s2</code>表在子查询中，子查询有一个独立的<code>SELECT</code>关键字，所以第二条记录的<code>id</code>值就是<code>2</code>。</p><p>但是这里大家需要特别注意，查询优化器可能对涉及子查询的查询语句进行重写，从而转换为连接查询。所以如果我们想知道查询优化器对某个包含子查询的语句是否进行了重写，直接查看执行计划就好了，比如说：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1 WHERE key1 IN (SELECT key3 FROM s2 WHERE common_field = &#39;a&#39;);</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+----------+---------+-------------------+------+----------+------------------------------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type | possible_keys | key      | key_len | ref               | rows | filtered | Extra                        |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+----------+---------+-------------------+------+----------+------------------------------+</span></span>
<span class="line"><span>|  1 | SIMPLE      | s2    | NULL       | ALL  | idx_key3      | NULL     | NULL    | NULL              | 9954 |    10.00 | Using where; Start temporary |</span></span>
<span class="line"><span>|  1 | SIMPLE      | s1    | NULL       | ref  | idx_key1      | idx_key1 | 303     | xiaohaizi.s2.key3 |    1 |   100.00 | End temporary                |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+----------+---------+-------------------+------+----------+------------------------------+</span></span>
<span class="line"><span>2 rows in set, 1 warning (0.00 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>可以看到，虽然我们的查询语句是一个子查询，但是执行计划中<code>s1</code>和<code>s2</code>表对应的记录的<code>id</code>值全部是<code>1</code>，这就表明了查询优化器将子查询转换为了连接查询。</p><p>对于包含<code>UNION</code>子句的查询语句来说，每个<code>SELECT</code>关键字对应一个<code>id</code>值也是没错的，不过还是有点儿特别的东西，比方说下边这个查询：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1  UNION SELECT * FROM s2;</span></span>
<span class="line"><span>+----+--------------+------------+------------+------+---------------+------+---------+------+------+----------+-----------------+</span></span>
<span class="line"><span>| id | select_type  | table      | partitions | type | possible_keys | key  | key_len | ref  | rows | filtered | Extra           |</span></span>
<span class="line"><span>+----+--------------+------------+------------+------+---------------+------+---------+------+------+----------+-----------------+</span></span>
<span class="line"><span>|  1 | PRIMARY      | s1         | NULL       | ALL  | NULL          | NULL | NULL    | NULL | 9688 |   100.00 | NULL            |</span></span>
<span class="line"><span>|  2 | UNION        | s2         | NULL       | ALL  | NULL          | NULL | NULL    | NULL | 9954 |   100.00 | NULL            |</span></span>
<span class="line"><span>| NULL | UNION RESULT | &lt;union1,2&gt; | NULL       | ALL  | NULL          | NULL | NULL    | NULL | NULL |     NULL | Using temporary |</span></span>
<span class="line"><span>+----+--------------+------------+------------+------+---------------+------+---------+------+------+----------+-----------------+</span></span>
<span class="line"><span>3 rows in set, 1 warning (0.00 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>这个语句的执行计划的第三条记录是个什么鬼？为毛<code>id</code>值是<code>NULL</code>，而且<code>table</code>列长的也怪怪的？大家别忘了<code>UNION</code>子句是干嘛用的，它会把多个查询的结果集合并起来并对结果集中的记录进行去重，怎么去重呢？<code>MySQL</code>使用的是内部的临时表。正如上边的查询计划中所示，<code>UNION</code>子句是为了把<code>id</code>为<code>1</code>的查询和<code>id</code>为<code>2</code>的查询的结果集合并起来并去重，所以在内部创建了一个名为<code>&lt;union1, 2&gt;</code>的临时表（就是执行计划第三条记录的<code>table</code>列的名称），<code>id</code>为<code>NULL</code>表明这个临时表是为了合并两个查询的结果集而创建的。</p><p>跟<code>UNION</code>对比起来，<code>UNION ALL</code>就不需要为最终的结果集进行去重，它只是单纯的把多个查询的结果集中的记录合并成一个并返回给用户，所以也就不需要使用临时表。所以在包含<code>UNION ALL</code>子句的查询的执行计划中，就没有那个<code>id</code>为<code>NULL</code>的记录，如下所示：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1  UNION ALL SELECT * FROM s2;</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+------+---------+------+------+----------+-------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type | possible_keys | key  | key_len | ref  | rows | filtered | Extra |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+------+---------+------+------+----------+-------+</span></span>
<span class="line"><span>|  1 | PRIMARY     | s1    | NULL       | ALL  | NULL          | NULL | NULL    | NULL | 9688 |   100.00 | NULL  |</span></span>
<span class="line"><span>|  2 | UNION       | s2    | NULL       | ALL  | NULL          | NULL | NULL    | NULL | 9954 |   100.00 | NULL  |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+------+---------+------+------+----------+-------+</span></span>
<span class="line"><span>2 rows in set, 1 warning (0.01 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h3 id="select-type" tabindex="-1">select_type <a class="header-anchor" href="#select-type" aria-label="Permalink to &quot;select_type&quot;">​</a></h3><p>通过上边的内容我们知道，一条大的查询语句里边可以包含若干个<code>SELECT</code>关键字，每个<code>SELECT</code>关键字代表着一个小的查询语句，而每个<code>SELECT</code>关键字的<code>FROM</code>子句中都可以包含若干张表（这些表用来做连接查询），每一张表都对应着执行计划输出中的一条记录，对于在同一个<code>SELECT</code>关键字中的表来说，它们的<code>id</code>值是相同的。</p><p>设计<code>MySQL</code>的大叔为每一个<code>SELECT</code>关键字代表的小查询都定义了一个称之为<code>select_type</code>的属性，意思是我们只要知道了某个小查询的<code>select_type</code>属性，就知道了这个小查询在整个大查询中扮演了一个什么角色，口说无凭，我们还是先来见识见识这个<code>select_type</code>都能取哪些值（为了精确起见，我们直接使用文档中的英文做简要描述，随后会进行详细解释的）：</p><table><thead><tr><th>名称</th><th>描述</th></tr></thead><tbody><tr><td><code>SIMPLE</code></td><td>Simple SELECT (not using UNION or subqueries)</td></tr><tr><td><code>PRIMARY</code></td><td>Outermost SELECT</td></tr><tr><td><code>UNION</code></td><td>Second or later SELECT statement in a UNION</td></tr><tr><td><code>UNION RESULT</code></td><td>Result of a UNION</td></tr><tr><td><code>SUBQUERY</code></td><td>First SELECT in subquery</td></tr><tr><td><code>DEPENDENT SUBQUERY</code></td><td>First SELECT in subquery, dependent on outer query</td></tr><tr><td><code>DEPENDENT UNION</code></td><td>Second or later SELECT statement in a UNION, dependent on outer query</td></tr><tr><td><code>DERIVED</code></td><td>Derived table</td></tr><tr><td><code>MATERIALIZED</code></td><td>Materialized subquery</td></tr><tr><td><code>UNCACHEABLE SUBQUERY</code></td><td>A subquery for which the result cannot be cached and must be re-evaluated for each row of the outer query</td></tr><tr><td><code>UNCACHEABLE UNION</code></td><td>The second or later select in a UNION that belongs to an uncacheable subquery (see UNCACHEABLE SUBQUERY)</td></tr></tbody></table><p>英文描述太简单，不知道说了啥？来详细瞅瞅里边儿的每个值都是干啥吃的：</p><ul><li><p><code>SIMPLE</code></p><p>查询语句中不包含<code>UNION</code>或者子查询的查询都算作是<code>SIMPLE</code>类型，比方说下边这个单表查询的<code>select_type</code>的值就是<code>SIMPLE</code>：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1;</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+------+---------+------+------+----------+-------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type | possible_keys | key  | key_len | ref  | rows | filtered | Extra |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+------+---------+------+------+----------+-------+</span></span>
<span class="line"><span>|  1 | SIMPLE      | s1    | NULL       | ALL  | NULL          | NULL | NULL    | NULL | 9688 |   100.00 | NULL  |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+------+---------+------+------+----------+-------+</span></span>
<span class="line"><span>1 row in set, 1 warning (0.00 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>当然，连接查询也算是<code>SIMPLE</code>类型，比如：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1 INNER JOIN s2;</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+------+---------+------+------+----------+---------------------------------------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type | possible_keys | key  | key_len | ref  | rows | filtered | Extra                                 |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+------+---------+------+------+----------+---------------------------------------+</span></span>
<span class="line"><span>|  1 | SIMPLE      | s1    | NULL       | ALL  | NULL          | NULL | NULL    | NULL | 9688 |   100.00 | NULL                                  |</span></span>
<span class="line"><span>|  1 | SIMPLE      | s2    | NULL       | ALL  | NULL          | NULL | NULL    | NULL | 9954 |   100.00 | Using join buffer (Block Nested Loop) |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+------+---------+------+------+----------+---------------------------------------+</span></span>
<span class="line"><span>2 rows in set, 1 warning (0.01 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div></li><li><p><code>PRIMARY</code></p><p>对于包含<code>UNION</code>、<code>UNION ALL</code>或者子查询的大查询来说，它是由几个小查询组成的，其中最左边的那个查询的<code>select_type</code>值就是<code>PRIMARY</code>，比方说：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1 UNION SELECT * FROM s2;</span></span>
<span class="line"><span>+----+--------------+------------+------------+------+---------------+------+---------+------+------+----------+-----------------+</span></span>
<span class="line"><span>| id | select_type  | table      | partitions | type | possible_keys | key  | key_len | ref  | rows | filtered | Extra           |</span></span>
<span class="line"><span>+----+--------------+------------+------------+------+---------------+------+---------+------+------+----------+-----------------+</span></span>
<span class="line"><span>|  1 | PRIMARY      | s1         | NULL       | ALL  | NULL          | NULL | NULL    | NULL | 9688 |   100.00 | NULL            |</span></span>
<span class="line"><span>|  2 | UNION        | s2         | NULL       | ALL  | NULL          | NULL | NULL    | NULL | 9954 |   100.00 | NULL            |</span></span>
<span class="line"><span>| NULL | UNION RESULT | &lt;union1,2&gt; | NULL       | ALL  | NULL          | NULL | NULL    | NULL | NULL |     NULL | Using temporary |</span></span>
<span class="line"><span>+----+--------------+------------+------------+------+---------------+------+---------+------+------+----------+-----------------+</span></span>
<span class="line"><span>3 rows in set, 1 warning (0.00 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>从结果中可以看到，最左边的小查询<code>SELECT * FROM s1</code>对应的是执行计划中的第一条记录，它的<code>select_type</code>值就是<code>PRIMARY</code>。</p></li><li><p><code>UNION</code></p><p>对于包含<code>UNION</code>或者<code>UNION ALL</code>的大查询来说，它是由几个小查询组成的，其中除了最左边的那个小查询以外，其余的小查询的<code>select_type</code>值就是<code>UNION</code>，可以对比上一个例子的效果，这就不多举例子了。</p></li><li><p><code>UNION RESULT</code></p><p><code>MySQL</code>选择使用临时表来完成<code>UNION</code>查询的去重工作，针对该临时表的查询的<code>select_type</code>就是<code>UNION RESULT</code>，例子上边有，就不赘述了。</p></li><li><p><code>SUBQUERY</code></p><p>如果包含子查询的查询语句不能够转为对应的<code>semi-join</code>的形式，并且该子查询是不相关子查询，并且查询优化器决定采用将该子查询物化的方案来执行该子查询时，该子查询的第一个<code>SELECT</code>关键字代表的那个查询的<code>select_type</code>就是<code>SUBQUERY</code>，比如下边这个查询：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1 WHERE key1 IN (SELECT key1 FROM s2) OR key3 = &#39;a&#39;;</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------+---------------+----------+---------+------+------+----------+-------------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type  | possible_keys | key      | key_len | ref  | rows | filtered | Extra       |</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------+---------------+----------+---------+------+------+----------+-------------+</span></span>
<span class="line"><span>|  1 | PRIMARY     | s1    | NULL       | ALL   | idx_key3      | NULL     | NULL    | NULL | 9688 |   100.00 | Using where |</span></span>
<span class="line"><span>|  2 | SUBQUERY    | s2    | NULL       | index | idx_key1      | idx_key1 | 303     | NULL | 9954 |   100.00 | Using index |</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------+---------------+----------+---------+------+------+----------+-------------+</span></span>
<span class="line"><span>2 rows in set, 1 warning (0.00 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>可以看到，外层查询的<code>select_type</code>就是<code>PRIMARY</code>，子查询的<code>select_type</code>就是<code>SUBQUERY</code>。需要大家注意的是，由于select_type为SUBQUERY的子查询会被物化，所以只需要执行一遍。</p></li><li><p><code>DEPENDENT SUBQUERY</code></p><p>如果包含子查询的查询语句不能够转为对应的<code>semi-join</code>的形式，并且该子查询是相关子查询，则该子查询的第一个<code>SELECT</code>关键字代表的那个查询的<code>select_type</code>就是<code>DEPENDENT SUBQUERY</code>，比如下边这个查询：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1 WHERE key1 IN (SELECT key1 FROM s2 WHERE s1.key2 = s2.key2) OR key3 = &#39;a&#39;;</span></span>
<span class="line"><span>+----+--------------------+-------+------------+------+-------------------+----------+---------+-------------------+------+----------+-------------+</span></span>
<span class="line"><span>| id | select_type        | table | partitions | type | possible_keys     | key      | key_len | ref               | rows | filtered | Extra       |</span></span>
<span class="line"><span>+----+--------------------+-------+------------+------+-------------------+----------+---------+-------------------+------+----------+-------------+</span></span>
<span class="line"><span>|  1 | PRIMARY            | s1    | NULL       | ALL  | idx_key3          | NULL     | NULL    | NULL              | 9688 |   100.00 | Using where |</span></span>
<span class="line"><span>|  2 | DEPENDENT SUBQUERY | s2    | NULL       | ref  | idx_key2,idx_key1 | idx_key2 | 5       | xiaohaizi.s1.key2 |    1 |    10.00 | Using where |</span></span>
<span class="line"><span>+----+--------------------+-------+------------+------+-------------------+----------+---------+-------------------+------+----------+-------------+</span></span>
<span class="line"><span>2 rows in set, 2 warnings (0.00 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>需要大家注意的是，select_type为DEPENDENT SUBQUERY的查询可能会被执行多次。</p></li><li><p><code>DEPENDENT UNION</code></p><p>在包含<code>UNION</code>或者<code>UNION ALL</code>的大查询中，如果各个小查询都依赖于外层查询的话，那除了最左边的那个小查询之外，其余的小查询的<code>select_type</code>的值就是<code>DEPENDENT UNION</code>。说的有些绕哈，比方说下边这个查询：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1 WHERE key1 IN (SELECT key1 FROM s2 WHERE key1 = &#39;a&#39; UNION SELECT key1 FROM s1 WHERE key1 = &#39;b&#39;);</span></span>
<span class="line"><span>+----+--------------------+------------+------------+------+---------------+----------+---------+-------+------+----------+--------------------------+</span></span>
<span class="line"><span>| id | select_type        | table      | partitions | type | possible_keys | key      | key_len | ref   | rows | filtered | Extra                    |</span></span>
<span class="line"><span>+----+--------------------+------------+------------+------+---------------+----------+---------+-------+------+----------+--------------------------+</span></span>
<span class="line"><span>|  1 | PRIMARY            | s1         | NULL       | ALL  | NULL          | NULL     | NULL    | NULL  | 9688 |   100.00 | Using where              |</span></span>
<span class="line"><span>|  2 | DEPENDENT SUBQUERY | s2         | NULL       | ref  | idx_key1      | idx_key1 | 303     | const |   12 |   100.00 | Using where; Using index |</span></span>
<span class="line"><span>|  3 | DEPENDENT UNION    | s1         | NULL       | ref  | idx_key1      | idx_key1 | 303     | const |    8 |   100.00 | Using where; Using index |</span></span>
<span class="line"><span>| NULL | UNION RESULT       | &lt;union2,3&gt; | NULL       | ALL  | NULL          | NULL     | NULL    | NULL  | NULL |     NULL | Using temporary          |</span></span>
<span class="line"><span>+----+--------------------+------------+------------+------+---------------+----------+---------+-------+------+----------+--------------------------+</span></span>
<span class="line"><span>4 rows in set, 1 warning (0.03 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>这个查询比较复杂啊，大查询里包含了一个子查询，子查询里又是由<code>UNION</code>连起来的两个小查询。从执行计划中可以看出来，<code>SELECT key1 FROM s2 WHERE key1 = &#39;a&#39;</code>这个小查询由于是子查询中第一个查询，所以它的<code>select_type</code>是<code>DEPENDENT SUBQUERY</code>，而<code>SELECT key1 FROM s1 WHERE key1 = &#39;b&#39;</code>这个查询的<code>select_type</code>就是<code>DEPENDENT UNION</code>。</p></li><li><p><code>DERIVED</code></p><p>对于采用物化的方式执行的包含派生表的查询，该派生表对应的子查询的<code>select_type</code>就是<code>DERIVED</code>，比方说下边这个查询：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM (SELECT key1, count(*) as c FROM s1 GROUP BY key1) AS derived_s1 where c &gt; 1;</span></span>
<span class="line"><span>+----+-------------+------------+------------+-------+---------------+----------+---------+------+------+----------+-------------+</span></span>
<span class="line"><span>| id | select_type | table      | partitions | type  | possible_keys | key      | key_len | ref  | rows | filtered | Extra       |</span></span>
<span class="line"><span>+----+-------------+------------+------------+-------+---------------+----------+---------+------+------+----------+-------------+</span></span>
<span class="line"><span>|  1 | PRIMARY     | &lt;derived2&gt; | NULL       | ALL   | NULL          | NULL     | NULL    | NULL | 9688 |    33.33 | Using where |</span></span>
<span class="line"><span>|  2 | DERIVED     | s1         | NULL       | index | idx_key1      | idx_key1 | 303     | NULL | 9688 |   100.00 | Using index |</span></span>
<span class="line"><span>+----+-------------+------------+------------+-------+---------------+----------+---------+------+------+----------+-------------+</span></span>
<span class="line"><span>2 rows in set, 1 warning (0.00 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>从执行计划中可以看出，<code>id</code>为<code>2</code>的记录就代表子查询的执行方式，它的<code>select_type</code>是<code>DERIVED</code>，说明该子查询是以物化的方式执行的。<code>id</code>为<code>1</code>的记录代表外层查询，大家注意看它的<code>table</code>列显示的是<code>&lt;derived2&gt;</code>，表示该查询是针对将派生表物化之后的表进行查询的。</p><blockquote><p>小贴士： 如果派生表可以通过和外层查询合并的方式执行的话，执行计划又是另一番景象，大家可以试试哈～</p></blockquote></li><li><p><code>MATERIALIZED</code></p><p>当查询优化器在执行包含子查询的语句时，选择将子查询物化之后与外层查询进行连接查询时，该子查询对应的<code>select_type</code>属性就是<code>MATERIALIZED</code>，比如下边这个查询：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1 WHERE key1 IN (SELECT key1 FROM s2);</span></span>
<span class="line"><span>+----+--------------+-------------+------------+--------+---------------+------------+---------+-------------------+------+----------+-------------+</span></span>
<span class="line"><span>| id | select_type  | table       | partitions | type   | possible_keys | key        | key_len | ref               | rows | filtered | Extra       |</span></span>
<span class="line"><span>+----+--------------+-------------+------------+--------+---------------+------------+---------+-------------------+------+----------+-------------+</span></span>
<span class="line"><span>|  1 | SIMPLE       | s1          | NULL       | ALL    | idx_key1      | NULL       | NULL    | NULL              | 9688 |   100.00 | Using where |</span></span>
<span class="line"><span>|  1 | SIMPLE       | &lt;subquery2&gt; | NULL       | eq_ref | &lt;auto_key&gt;    | &lt;auto_key&gt; | 303     | xiaohaizi.s1.key1 |    1 |   100.00 | NULL        |</span></span>
<span class="line"><span>|  2 | MATERIALIZED | s2          | NULL       | index  | idx_key1      | idx_key1   | 303     | NULL              | 9954 |   100.00 | Using index |</span></span>
<span class="line"><span>+----+--------------+-------------+------------+--------+---------------+------------+---------+-------------------+------+----------+-------------+</span></span>
<span class="line"><span>3 rows in set, 1 warning (0.01 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>执行计划的第三条记录的<code>id</code>值为<code>2</code>，说明该条记录对应的是一个单表查询，从它的<code>select_type</code>值为<code>MATERIALIZED</code>可以看出，查询优化器是要把子查询先转换成物化表。然后看执行计划的前两条记录的<code>id</code>值都为<code>1</code>，说明这两条记录对应的表进行连接查询，需要注意的是第二条记录的<code>table</code>列的值是<code>&lt;subquery2&gt;</code>，说明该表其实就是<code>id</code>为<code>2</code>对应的子查询执行之后产生的物化表，然后将<code>s1</code>和该物化表进行连接查询。</p></li><li><p><code>UNCACHEABLE SUBQUERY</code></p><p>不常用，就不多唠叨了。</p></li><li><p><code>UNCACHEABLE UNION</code></p><p>不常用，就不多唠叨了。</p></li></ul><h3 id="partitions" tabindex="-1">partitions <a class="header-anchor" href="#partitions" aria-label="Permalink to &quot;partitions&quot;">​</a></h3><p>由于我们压根儿就没唠叨过分区是个啥，所以这个输出列我们也就不说了哈，一般情况下我们的查询语句的执行计划的<code>partitions</code>列的值都是<code>NULL</code>。</p><h3 id="type" tabindex="-1">type <a class="header-anchor" href="#type" aria-label="Permalink to &quot;type&quot;">​</a></h3><p>我们前边说过执行计划的一条记录就代表着<code>MySQL</code>对某个表的执行查询时的访问方法，其中的<code>type</code>列就表明了这个访问方法是个啥，比方说下边这个查询：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1 WHERE key1 = &#39;a&#39;;</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+----------+---------+-------+------+----------+-------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type | possible_keys | key      | key_len | ref   | rows | filtered | Extra |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+----------+---------+-------+------+----------+-------+</span></span>
<span class="line"><span>|  1 | SIMPLE      | s1    | NULL       | ref  | idx_key1      | idx_key1 | 303     | const |    8 |   100.00 | NULL  |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+----------+---------+-------+------+----------+-------+</span></span>
<span class="line"><span>1 row in set, 1 warning (0.04 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>可以看到<code>type</code>列的值是<code>ref</code>，表明<code>MySQL</code>即将使用<code>ref</code>访问方法来执行对<code>s1</code>表的查询。但是我们之前只唠叨过对使用<code>InnoDB</code>存储引擎的表进行单表访问的一些访问方法，完整的访问方法如下：<code>system</code>，<code>const</code>，<code>eq_ref</code>，<code>ref</code>，<code>fulltext</code>，<code>ref_or_null</code>，<code>index_merge</code>，<code>unique_subquery</code>，<code>index_subquery</code>，<code>range</code>，<code>index</code>，<code>ALL</code>。当然我们还要详细唠叨一下哈：</p><ul><li><p><code>system</code></p><p>当表中只有一条记录并且该表使用的存储引擎的统计数据是精确的，比如MyISAM、Memory，那么对该表的访问方法就是<code>system</code>。比方说我们新建一个<code>MyISAM</code>表，并为其插入一条记录：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; CREATE TABLE t(i int) Engine=MyISAM;</span></span>
<span class="line"><span>Query OK, 0 rows affected (0.05 sec)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>mysql&gt; INSERT INTO t VALUES(1);</span></span>
<span class="line"><span>Query OK, 1 row affected (0.01 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>然后我们看一下查询这个表的执行计划：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM t;</span></span>
<span class="line"><span>+----+-------------+-------+------------+--------+---------------+------+---------+------+------+----------+-------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type   | possible_keys | key  | key_len | ref  | rows | filtered | Extra |</span></span>
<span class="line"><span>+----+-------------+-------+------------+--------+---------------+------+---------+------+------+----------+-------+</span></span>
<span class="line"><span>|  1 | SIMPLE      | t     | NULL       | system | NULL          | NULL | NULL    | NULL |    1 |   100.00 | NULL  |</span></span>
<span class="line"><span>+----+-------------+-------+------------+--------+---------------+------+---------+------+------+----------+-------+</span></span>
<span class="line"><span>1 row in set, 1 warning (0.00 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>可以看到<code>type</code>列的值就是<code>system</code>了。</p><blockquote><p>小贴士： 你可以把表改成使用InnoDB存储引擎，试试看执行计划的type列是什么。</p></blockquote></li><li><p><code>const</code></p><p>这个我们前边唠叨过，就是当我们根据主键或者唯一二级索引列与常数进行等值匹配时，对单表的访问方法就是<code>const</code>，比如：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1 WHERE id = 5;</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------+---------------+---------+---------+-------+------+----------+-------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type  | possible_keys | key     | key_len | ref   | rows | filtered | Extra |</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------+---------------+---------+---------+-------+------+----------+-------+</span></span>
<span class="line"><span>|  1 | SIMPLE      | s1    | NULL       | const | PRIMARY       | PRIMARY | 4       | const |    1 |   100.00 | NULL  |</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------+---------------+---------+---------+-------+------+----------+-------+</span></span>
<span class="line"><span>1 row in set, 1 warning (0.01 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div></li><li><p><code>eq_ref</code></p><p>在连接查询时，如果被驱动表是通过主键或者唯一二级索引列等值匹配的方式进行访问的（如果该主键或者唯一二级索引是联合索引的话，所有的索引列都必须进行等值比较），则对该被驱动表的访问方法就是<code>eq_ref</code>，比方说：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1 INNER JOIN s2 ON s1.id = s2.id;</span></span>
<span class="line"><span>+----+-------------+-------+------------+--------+---------------+---------+---------+-----------------+------+----------+-------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type   | possible_keys | key     | key_len | ref             | rows | filtered | Extra |</span></span>
<span class="line"><span>+----+-------------+-------+------------+--------+---------------+---------+---------+-----------------+------+----------+-------+</span></span>
<span class="line"><span>|  1 | SIMPLE      | s1    | NULL       | ALL    | PRIMARY       | NULL    | NULL    | NULL            | 9688 |   100.00 | NULL  |</span></span>
<span class="line"><span>|  1 | SIMPLE      | s2    | NULL       | eq_ref | PRIMARY       | PRIMARY | 4       | xiaohaizi.s1.id |    1 |   100.00 | NULL  |</span></span>
<span class="line"><span>+----+-------------+-------+------------+--------+---------------+---------+---------+-----------------+------+----------+-------+</span></span>
<span class="line"><span>2 rows in set, 1 warning (0.01 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>从执行计划的结果中可以看出，<code>MySQL</code>打算将<code>s1</code>作为驱动表，<code>s2</code>作为被驱动表，重点关注<code>s2</code>的访问方法是<code>eq_ref</code>，表明在访问<code>s2</code>表的时候可以通过主键的等值匹配来进行访问。</p></li><li><p><code>ref</code></p><p>当通过普通的二级索引列与常量进行等值匹配时来查询某个表，那么对该表的访问方法就可能是<code>ref</code>，最开始举过例子了，就不重复举例了。</p></li><li><p><code>fulltext</code></p><p>全文索引，我们没有细讲过，跳过～</p></li><li><p><code>ref_or_null</code></p><p>当对普通二级索引进行等值匹配查询，该索引列的值也可以是<code>NULL</code>值时，那么对该表的访问方法就可能是<code>ref_or_null</code>，比如说：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1 WHERE key1 = &#39;a&#39; OR key1 IS NULL;</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------------+---------------+----------+---------+-------+------+----------+-----------------------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type        | possible_keys | key      | key_len | ref   | rows | filtered | Extra                 |</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------------+---------------+----------+---------+-------+------+----------+-----------------------+</span></span>
<span class="line"><span>|  1 | SIMPLE      | s1    | NULL       | ref_or_null | idx_key1      | idx_key1 | 303     | const |    9 |   100.00 | Using index condition |</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------------+---------------+----------+---------+-------+------+----------+-----------------------+</span></span>
<span class="line"><span>1 row in set, 1 warning (0.01 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div></li><li><p><code>index_merge</code></p><p>一般情况下对于某个表的查询只能使用到一个索引，但我们唠叨单表访问方法时特意强调了在某些场景下可以使用<code>Intersection</code>、<code>Union</code>、<code>Sort-Union</code>这三种索引合并的方式来执行查询，忘掉的回去补一下哈，我们看一下执行计划中是怎么体现<code>MySQL</code>使用索引合并的方式来对某个表执行查询的：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1 WHERE key1 = &#39;a&#39; OR key3 = &#39;a&#39;;</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------------+-------------------+-------------------+---------+------+------+----------+---------------------------------------------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type        | possible_keys     | key               | key_len | ref  | rows | filtered | Extra                                       |</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------------+-------------------+-------------------+---------+------+------+----------+---------------------------------------------+</span></span>
<span class="line"><span>|  1 | SIMPLE      | s1    | NULL       | index_merge | idx_key1,idx_key3 | idx_key1,idx_key3 | 303,303 | NULL |   14 |   100.00 | Using union(idx_key1,idx_key3); Using where |</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------------+-------------------+-------------------+---------+------+------+----------+---------------------------------------------+</span></span>
<span class="line"><span>1 row in set, 1 warning (0.01 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>从执行计划的<code>type</code>列的值是<code>index_merge</code>就可以看出，<code>MySQL</code>打算使用索引合并的方式来执行对<code>s1</code>表的查询。</p></li><li><p><code>unique_subquery</code></p><p>类似于两表连接中被驱动表的<code>eq_ref</code>访问方法，<code>unique_subquery</code>是针对在一些包含<code>IN</code>子查询的查询语句中，如果查询优化器决定将<code>IN</code>子查询转换为<code>EXISTS</code>子查询，而且子查询可以使用到主键进行等值匹配的话，那么该子查询执行计划的<code>type</code>列的值就是<code>unique_subquery</code>，比如下边的这个查询语句：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1 WHERE key2 IN (SELECT id FROM s2 where s1.key1 = s2.key1) OR key3 = &#39;a&#39;;</span></span>
<span class="line"><span>+----+--------------------+-------+------------+-----------------+------------------+---------+---------+------+------+----------+-------------+</span></span>
<span class="line"><span>| id | select_type        | table | partitions | type            | possible_keys    | key     | key_len | ref  | rows | filtered | Extra       |</span></span>
<span class="line"><span>+----+--------------------+-------+------------+-----------------+------------------+---------+---------+------+------+----------+-------------+</span></span>
<span class="line"><span>|  1 | PRIMARY            | s1    | NULL       | ALL             | idx_key3         | NULL    | NULL    | NULL | 9688 |   100.00 | Using where |</span></span>
<span class="line"><span>|  2 | DEPENDENT SUBQUERY | s2    | NULL       | unique_subquery | PRIMARY,idx_key1 | PRIMARY | 4       | func |    1 |    10.00 | Using where |</span></span>
<span class="line"><span>+----+--------------------+-------+------------+-----------------+------------------+---------+---------+------+------+----------+-------------+</span></span>
<span class="line"><span>2 rows in set, 2 warnings (0.00 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>可以看到执行计划的第二条记录的<code>type</code>值就是<code>unique_subquery</code>，说明在执行子查询时会使用到<code>id</code>列的索引。</p></li><li><p><code>index_subquery</code></p><p><code>index_subquery</code>与<code>unique_subquery</code>类似，只不过访问子查询中的表时使用的是普通的索引，比如这样：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1 WHERE common_field IN (SELECT key3 FROM s2 where s1.key1 = s2.key1) OR key3 = &#39;a&#39;;</span></span>
<span class="line"><span>+----+--------------------+-------+------------+----------------+-------------------+----------+---------+------+------+----------+-------------+</span></span>
<span class="line"><span>| id | select_type        | table | partitions | type           | possible_keys     | key      | key_len | ref  | rows | filtered | Extra       |</span></span>
<span class="line"><span>+----+--------------------+-------+------------+----------------+-------------------+----------+---------+------+------+----------+-------------+</span></span>
<span class="line"><span>|  1 | PRIMARY            | s1    | NULL       | ALL            | idx_key3          | NULL     | NULL    | NULL | 9688 |   100.00 | Using where |</span></span>
<span class="line"><span>|  2 | DEPENDENT SUBQUERY | s2    | NULL       | index_subquery | idx_key1,idx_key3 | idx_key3 | 303     | func |    1 |    10.00 | Using where |</span></span>
<span class="line"><span>+----+--------------------+-------+------------+----------------+-------------------+----------+---------+------+------+----------+-------------+</span></span>
<span class="line"><span>2 rows in set, 2 warnings (0.01 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div></li><li><p><code>range</code></p><p>如果使用索引获取某些<code>范围区间</code>的记录，那么就可能使用到<code>range</code>访问方法，比如下边的这个查询：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1 WHERE key1 IN (&#39;a&#39;, &#39;b&#39;, &#39;c&#39;);</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------+---------------+----------+---------+------+------+----------+-----------------------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type  | possible_keys | key      | key_len | ref  | rows | filtered | Extra                 |</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------+---------------+----------+---------+------+------+----------+-----------------------+</span></span>
<span class="line"><span>|  1 | SIMPLE      | s1    | NULL       | range | idx_key1      | idx_key1 | 303     | NULL |   27 |   100.00 | Using index condition |</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------+---------------+----------+---------+------+------+----------+-----------------------+</span></span>
<span class="line"><span>1 row in set, 1 warning (0.01 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>或者：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1 WHERE key1 &gt; &#39;a&#39; AND key1 &lt; &#39;b&#39;;</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------+---------------+----------+---------+------+------+----------+-----------------------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type  | possible_keys | key      | key_len | ref  | rows | filtered | Extra                 |</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------+---------------+----------+---------+------+------+----------+-----------------------+</span></span>
<span class="line"><span>|  1 | SIMPLE      | s1    | NULL       | range | idx_key1      | idx_key1 | 303     | NULL |  294 |   100.00 | Using index condition |</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------+---------------+----------+---------+------+------+----------+-----------------------+</span></span>
<span class="line"><span>1 row in set, 1 warning (0.00 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div></li><li><p><code>index</code></p><p>当我们可以使用索引覆盖，但需要扫描全部的索引记录时，该表的访问方法就是<code>index</code>，比如这样：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT key_part2 FROM s1 WHERE key_part3 = &#39;a&#39;;</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------+---------------+--------------+---------+------+------+----------+--------------------------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type  | possible_keys | key          | key_len | ref  | rows | filtered | Extra                    |</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------+---------------+--------------+---------+------+------+----------+--------------------------+</span></span>
<span class="line"><span>|  1 | SIMPLE      | s1    | NULL       | index | NULL          | idx_key_part | 909     | NULL | 9688 |    10.00 | Using where; Using index |</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------+---------------+--------------+---------+------+------+----------+--------------------------+</span></span>
<span class="line"><span>1 row in set, 1 warning (0.00 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>上述查询中的搜索列表中只有<code>key_part2</code>一个列，而且搜索条件中也只有<code>key_part3</code>一个列，这两个列又恰好包含在<code>idx_key_part</code>这个索引中，可是搜索条件<code>key_part3</code>不能直接使用该索引进行<code>ref</code>或者<code>range</code>方式的访问，只能扫描整个<code>idx_key_part</code>索引的记录，所以查询计划的<code>type</code>列的值就是<code>index</code>。</p><blockquote><p>小贴士： 再一次强调，对于使用InnoDB存储引擎的表来说，二级索引的记录只包含索引列和主键列的值，而聚簇索引中包含用户定义的全部列以及一些隐藏列，所以扫描二级索引的代价比直接全表扫描，也就是扫描聚簇索引的代价更低一些。</p></blockquote></li><li><p><code>ALL</code></p><p>最熟悉的全表扫描，就不多唠叨了，直接看例子：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1;</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+------+---------+------+------+----------+-------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type | possible_keys | key  | key_len | ref  | rows | filtered | Extra |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+------+---------+------+------+----------+-------+</span></span>
<span class="line"><span>|  1 | SIMPLE      | s1    | NULL       | ALL  | NULL          | NULL | NULL    | NULL | 9688 |   100.00 | NULL  |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+------+---------+------+------+----------+-------+</span></span>
<span class="line"><span>1 row in set, 1 warning (0.00 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div></li></ul><p>一般来说，这些访问方法按照我们介绍它们的顺序性能依次变差。其中除了<code>All</code>这个访问方法外，其余的访问方法都能用到索引，除了<code>index_merge</code>访问方法外，其余的访问方法都最多只能用到一个索引。</p><h3 id="possible-keys和key" tabindex="-1">possible_keys和key <a class="header-anchor" href="#possible-keys和key" aria-label="Permalink to &quot;possible_keys和key&quot;">​</a></h3><p>在<code>EXPLAIN</code>语句输出的执行计划中，<code>possible_keys</code>列表示在某个查询语句中，对某个表执行单表查询时可能用到的索引有哪些，<code>key</code>列表示实际用到的索引有哪些，比方说下边这个查询：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1 WHERE key1 &gt; &#39;z&#39; AND key3 = &#39;a&#39;;</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+-------------------+----------+---------+-------+------+----------+-------------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type | possible_keys     | key      | key_len | ref   | rows | filtered | Extra       |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+-------------------+----------+---------+-------+------+----------+-------------+</span></span>
<span class="line"><span>|  1 | SIMPLE      | s1    | NULL       | ref  | idx_key1,idx_key3 | idx_key3 | 303     | const |    6 |     2.75 | Using where |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+-------------------+----------+---------+-------+------+----------+-------------+</span></span>
<span class="line"><span>1 row in set, 1 warning (0.01 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>上述执行计划的<code>possible_keys</code>列的值是<code>idx_key1,idx_key3</code>，表示该查询可能使用到<code>idx_key1,idx_key3</code>两个索引，然后<code>key</code>列的值是<code>idx_key3</code>，表示经过查询优化器计算使用不同索引的成本后，最后决定使用<code>idx_key3</code>来执行查询比较划算。</p><p>不过有一点比较特别，就是在使用<code>index</code>访问方法来查询某个表时，<code>possible_keys</code>列是空的，而<code>key</code>列展示的是实际使用到的索引，比如这样：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT key_part2 FROM s1 WHERE key_part3 = &#39;a&#39;;</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------+---------------+--------------+---------+------+------+----------+--------------------------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type  | possible_keys | key          | key_len | ref  | rows | filtered | Extra                    |</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------+---------------+--------------+---------+------+------+----------+--------------------------+</span></span>
<span class="line"><span>|  1 | SIMPLE      | s1    | NULL       | index | NULL          | idx_key_part | 909     | NULL | 9688 |    10.00 | Using where; Using index |</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------+---------------+--------------+---------+------+------+----------+--------------------------+</span></span>
<span class="line"><span>1 row in set, 1 warning (0.00 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>另外需要注意的一点是，possible_keys列中的值并不是越多越好，可能使用的索引越多，查询优化器计算查询成本时就得花费更长时间，所以如果可以的话，尽量删除那些用不到的索引。</p><h3 id="key-len" tabindex="-1">key_len <a class="header-anchor" href="#key-len" aria-label="Permalink to &quot;key_len&quot;">​</a></h3><p><code>key_len</code>列表示当优化器决定使用某个索引执行查询时，该索引记录的最大长度，它是由这三个部分构成的：</p><ul><li>对于使用固定长度类型的索引列来说，它实际占用的存储空间的最大长度就是该固定值，对于指定字符集的变长类型的索引列来说，比如某个索引列的类型是<code>VARCHAR(100)</code>，使用的字符集是<code>utf8</code>，那么该列实际占用的最大存储空间就是<code>100 × 3 = 300</code>个字节。</li><li>如果该索引列可以存储<code>NULL</code>值，则<code>key_len</code>比不可以存储<code>NULL</code>值时多1个字节。</li><li>对于变长字段来说，都会有2个字节的空间来存储该变长列的实际长度。</li></ul><p>比如下边这个查询：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1 WHERE id = 5;</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------+---------------+---------+---------+-------+------+----------+-------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type  | possible_keys | key     | key_len | ref   | rows | filtered | Extra |</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------+---------------+---------+---------+-------+------+----------+-------+</span></span>
<span class="line"><span>|  1 | SIMPLE      | s1    | NULL       | const | PRIMARY       | PRIMARY | 4       | const |    1 |   100.00 | NULL  |</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------+---------------+---------+---------+-------+------+----------+-------+</span></span>
<span class="line"><span>1 row in set, 1 warning (0.01 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>由于<code>id</code>列的类型是<code>INT</code>，并且不可以存储<code>NULL</code>值，所以在使用该列的索引时<code>key_len</code>大小就是<code>4</code>。当索引列可以存储<code>NULL</code>值时，比如：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1 WHERE key2 = 5;</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------+---------------+----------+---------+-------+------+----------+-------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type  | possible_keys | key      | key_len | ref   | rows | filtered | Extra |</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------+---------------+----------+---------+-------+------+----------+-------+</span></span>
<span class="line"><span>|  1 | SIMPLE      | s1    | NULL       | const | idx_key2      | idx_key2 | 5       | const |    1 |   100.00 | NULL  |</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------+---------------+----------+---------+-------+------+----------+-------+</span></span>
<span class="line"><span>1 row in set, 1 warning (0.00 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>可以看到<code>key_len</code>列就变成了<code>5</code>，比使用<code>id</code>列的索引时多了<code>1</code>。</p><p>对于可变长度的索引列来说，比如下边这个查询：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1 WHERE key1 = &#39;a&#39;;</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+----------+---------+-------+------+----------+-------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type | possible_keys | key      | key_len | ref   | rows | filtered | Extra |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+----------+---------+-------+------+----------+-------+</span></span>
<span class="line"><span>|  1 | SIMPLE      | s1    | NULL       | ref  | idx_key1      | idx_key1 | 303     | const |    8 |   100.00 | NULL  |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+----------+---------+-------+------+----------+-------+</span></span>
<span class="line"><span>1 row in set, 1 warning (0.00 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>由于<code>key1</code>列的类型是<code>VARCHAR(100)</code>，所以该列实际最多占用的存储空间就是<code>300</code>字节，又因为该列允许存储<code>NULL</code>值，所以<code>key_len</code>需要加<code>1</code>，又因为该列是可变长度列，所以<code>key_len</code>需要加<code>2</code>，所以最后<code>ken_len</code>的值就是<code>303</code>。</p><p>有的同学可能有疑问：你在前边唠叨<code>InnoDB</code>行格式的时候不是说，存储变长字段的实际长度不是可能占用1个字节或者2个字节么？为什么现在不管三七二十一都用了<code>2</code>个字节？这里需要强调的一点是，执行计划的生成是在<code>MySQL server</code>层中的功能，并不是针对具体某个存储引擎的功能，设计<code>MySQL</code>的大叔在执行计划中输出<code>key_len</code>列主要是为了让我们区分某个使用联合索引的查询具体用了几个索引列，而不是为了准确的说明针对某个具体存储引擎存储变长字段的实际长度占用的空间到底是占用1个字节还是2个字节。比方说下边这个使用到联合索引<code>idx_key_part</code>的查询：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1 WHERE key_part1 = &#39;a&#39;;</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+--------------+---------+-------+------+----------+-------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type | possible_keys | key          | key_len | ref   | rows | filtered | Extra |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+--------------+---------+-------+------+----------+-------+</span></span>
<span class="line"><span>|  1 | SIMPLE      | s1    | NULL       | ref  | idx_key_part  | idx_key_part | 303     | const |   12 |   100.00 | NULL  |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+--------------+---------+-------+------+----------+-------+</span></span>
<span class="line"><span>1 row in set, 1 warning (0.00 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>我们可以从执行计划的<code>key_len</code>列中看到值是<code>303</code>，这意味着<code>MySQL</code>在执行上述查询中只能用到<code>idx_key_part</code>索引的一个索引列，而下边这个查询：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1 WHERE key_part1 = &#39;a&#39; AND key_part2 = &#39;b&#39;;</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+--------------+---------+-------------+------+----------+-------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type | possible_keys | key          | key_len | ref         | rows | filtered | Extra |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+--------------+---------+-------------+------+----------+-------+</span></span>
<span class="line"><span>|  1 | SIMPLE      | s1    | NULL       | ref  | idx_key_part  | idx_key_part | 606     | const,const |    1 |   100.00 | NULL  |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+--------------+---------+-------------+------+----------+-------+</span></span>
<span class="line"><span>1 row in set, 1 warning (0.01 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>这个查询的执行计划的<code>ken_len</code>列的值是<code>606</code>，说明执行这个查询的时候可以用到联合索引<code>idx_key_part</code>的两个索引列。</p><h3 id="ref" tabindex="-1">ref <a class="header-anchor" href="#ref" aria-label="Permalink to &quot;ref&quot;">​</a></h3><p>当使用索引列等值匹配的条件去执行查询时，也就是在访问方法是<code>const</code>、<code>eq_ref</code>、<code>ref</code>、<code>ref_or_null</code>、<code>unique_subquery</code>、<code>index_subquery</code>其中之一时，<code>ref</code>列展示的就是与索引列作等值匹配的东东是个啥，比如只是一个常数或者是某个列。大家看下边这个查询：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1 WHERE key1 = &#39;a&#39;;</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+----------+---------+-------+------+----------+-------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type | possible_keys | key      | key_len | ref   | rows | filtered | Extra |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+----------+---------+-------+------+----------+-------+</span></span>
<span class="line"><span>|  1 | SIMPLE      | s1    | NULL       | ref  | idx_key1      | idx_key1 | 303     | const |    8 |   100.00 | NULL  |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+----------+---------+-------+------+----------+-------+</span></span>
<span class="line"><span>1 row in set, 1 warning (0.01 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>可以看到<code>ref</code>列的值是<code>const</code>，表明在使用<code>idx_key1</code>索引执行查询时，与<code>key1</code>列作等值匹配的对象是一个常数，当然有时候更复杂一点：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1 INNER JOIN s2 ON s1.id = s2.id;</span></span>
<span class="line"><span>+----+-------------+-------+------------+--------+---------------+---------+---------+-----------------+------+----------+-------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type   | possible_keys | key     | key_len | ref             | rows | filtered | Extra |</span></span>
<span class="line"><span>+----+-------------+-------+------------+--------+---------------+---------+---------+-----------------+------+----------+-------+</span></span>
<span class="line"><span>|  1 | SIMPLE      | s1    | NULL       | ALL    | PRIMARY       | NULL    | NULL    | NULL            | 9688 |   100.00 | NULL  |</span></span>
<span class="line"><span>|  1 | SIMPLE      | s2    | NULL       | eq_ref | PRIMARY       | PRIMARY | 4       | xiaohaizi.s1.id |    1 |   100.00 | NULL  |</span></span>
<span class="line"><span>+----+-------------+-------+------------+--------+---------------+---------+---------+-----------------+------+----------+-------+</span></span>
<span class="line"><span>2 rows in set, 1 warning (0.00 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>可以看到对被驱动表<code>s2</code>的访问方法是<code>eq_ref</code>，而对应的<code>ref</code>列的值是<code>xiaohaizi.s1.id</code>，这说明在对被驱动表进行访问时会用到<code>PRIMARY</code>索引，也就是聚簇索引与一个列进行等值匹配的条件，于<code>s2</code>表的<code>id</code>作等值匹配的对象就是<code>xiaohaizi.s1.id</code>列（注意这里把数据库名也写出来了）。</p><p>有的时候与索引列进行等值匹配的对象是一个函数，比方说下边这个查询：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1 INNER JOIN s2 ON s2.key1 = UPPER(s1.key1);</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+----------+---------+------+------+----------+-----------------------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type | possible_keys | key      | key_len | ref  | rows | filtered | Extra                 |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+----------+---------+------+------+----------+-----------------------+</span></span>
<span class="line"><span>|  1 | SIMPLE      | s1    | NULL       | ALL  | NULL          | NULL     | NULL    | NULL | 9688 |   100.00 | NULL                  |</span></span>
<span class="line"><span>|  1 | SIMPLE      | s2    | NULL       | ref  | idx_key1      | idx_key1 | 303     | func |    1 |   100.00 | Using index condition |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+----------+---------+------+------+----------+-----------------------+</span></span>
<span class="line"><span>2 rows in set, 1 warning (0.00 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>我们看执行计划的第二条记录，可以看到对<code>s2</code>表采用<code>ref</code>访问方法执行查询，然后在查询计划的<code>ref</code>列里输出的是<code>func</code>，说明与<code>s2</code>表的<code>key1</code>列进行等值匹配的对象是一个函数。</p><h3 id="rows" tabindex="-1">rows <a class="header-anchor" href="#rows" aria-label="Permalink to &quot;rows&quot;">​</a></h3><p>如果查询优化器决定使用全表扫描的方式对某个表执行查询时，执行计划的<code>rows</code>列就代表预计需要扫描的行数，如果使用索引来执行查询时，执行计划的<code>rows</code>列就代表预计扫描的索引记录行数。比如下边这个查询：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1 WHERE key1 &gt; &#39;z&#39;;</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------+---------------+----------+---------+------+------+----------+-----------------------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type  | possible_keys | key      | key_len | ref  | rows | filtered | Extra                 |</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------+---------------+----------+---------+------+------+----------+-----------------------+</span></span>
<span class="line"><span>|  1 | SIMPLE      | s1    | NULL       | range | idx_key1      | idx_key1 | 303     | NULL |  266 |   100.00 | Using index condition |</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------+---------------+----------+---------+------+------+----------+-----------------------+</span></span>
<span class="line"><span>1 row in set, 1 warning (0.00 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>我们看到执行计划的<code>rows</code>列的值是<code>266</code>，这意味着查询优化器在经过分析使用<code>idx_key1</code>进行查询的成本之后，觉得满足<code>key1 &gt; &#39;z&#39;</code>这个条件的记录只有<code>266</code>条。</p><h3 id="filtered" tabindex="-1">filtered <a class="header-anchor" href="#filtered" aria-label="Permalink to &quot;filtered&quot;">​</a></h3><p>之前在分析连接查询的成本时提出过一个<code>condition filtering</code>的概念，就是<code>MySQL</code>在计算驱动表扇出时采用的一个策略：</p><ul><li>如果使用的是全表扫描的方式执行的单表查询，那么计算驱动表扇出时需要估计出满足搜索条件的记录到底有多少条。</li><li>如果使用的是索引执行的单表扫描，那么计算驱动表扇出的时候需要估计出满足除使用到对应索引的搜索条件外的其他搜索条件的记录有多少条。</li></ul><p>比方说下边这个查询：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1 WHERE key1 &gt; &#39;z&#39; AND common_field = &#39;a&#39;;</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------+---------------+----------+---------+------+------+----------+------------------------------------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type  | possible_keys | key      | key_len | ref  | rows | filtered | Extra                              |</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------+---------------+----------+---------+------+------+----------+------------------------------------+</span></span>
<span class="line"><span>|  1 | SIMPLE      | s1    | NULL       | range | idx_key1      | idx_key1 | 303     | NULL |  266 |    10.00 | Using index condition; Using where |</span></span>
<span class="line"><span>+----+-------------+-------+------------+-------+---------------+----------+---------+------+------+----------+------------------------------------+</span></span>
<span class="line"><span>1 row in set, 1 warning (0.00 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>从执行计划的<code>key</code>列中可以看出来，该查询使用<code>idx_key1</code>索引来执行查询，从<code>rows</code>列可以看出满足<code>key1 &gt; &#39;z&#39;</code>的记录有<code>266</code>条。执行计划的<code>filtered</code>列就代表查询优化器预测在这<code>266</code>条记录中，有多少条记录满足其余的搜索条件，也就是<code>common_field = &#39;a&#39;</code>这个条件的百分比。此处<code>filtered</code>列的值是<code>10.00</code>，说明查询优化器预测在<code>266</code>条记录中有<code>10.00%</code>的记录满足<code>common_field = &#39;a&#39;</code>这个条件。</p><p>对于单表查询来说，这个<code>filtered</code>列的值没什么意义，我们更关注在连接查询中驱动表对应的执行计划记录的<code>filtered</code>值，比方说下边这个查询：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; EXPLAIN SELECT * FROM s1 INNER JOIN s2 ON s1.key1 = s2.key1 WHERE s1.common_field = &#39;a&#39;;</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+----------+---------+-------------------+------+----------+-------------+</span></span>
<span class="line"><span>| id | select_type | table | partitions | type | possible_keys | key      | key_len | ref               | rows | filtered | Extra       |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+----------+---------+-------------------+------+----------+-------------+</span></span>
<span class="line"><span>|  1 | SIMPLE      | s1    | NULL       | ALL  | idx_key1      | NULL     | NULL    | NULL              | 9688 |    10.00 | Using where |</span></span>
<span class="line"><span>|  1 | SIMPLE      | s2    | NULL       | ref  | idx_key1      | idx_key1 | 303     | xiaohaizi.s1.key1 |    1 |   100.00 | NULL        |</span></span>
<span class="line"><span>+----+-------------+-------+------------+------+---------------+----------+---------+-------------------+------+----------+-------------+</span></span>
<span class="line"><span>2 rows in set, 1 warning (0.00 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>从执行计划中可以看出来，查询优化器打算把<code>s1</code>当作驱动表，<code>s2</code>当作被驱动表。我们可以看到驱动表<code>s1</code>表的执行计划的<code>rows</code>列为<code>9688</code>， <code>filtered</code>列为<code>10.00</code>，这意味着驱动表<code>s1</code>的扇出值就是<code>9688 × 10.00% = 968.8</code>，这说明还要对被驱动表执行大约<code>968</code>次查询。</p>`,100);function b(n,u,L,m,y,E){return c(),a("div",null,[s("h1",r,[p(l(n.$frontmatter.title)+" ",1),o]),t])}const N=e(d,[["render",b]]);export{k as __pageData,N as default};
